CustomField.formula:
IF( RecordType.DeveloperName = 'Shift_Demand', 
/* SHIFT DEMAND RECORD TYPE */

  IF( sirenum__Cancelled__c = true, 
    'Shift Cancelled', 
     IF(
        ISPICKVAL(Reconfirmed__c, 'Both'),
         'Reconfirm',
           IF(
             ISPICKVAL(Reconfirmed__c, 'Reconfirmed with Employee'),
              'Reconfirm with Employee',
                IF(
                    ISPICKVAL(Reconfirmed__c, 'Reconfirmed with Facility'),
                    'Reconfirm with Facility',
    IF( sirenum__Scheduled_Start_Time__c >= NOW(), 'Waiting', 'Unable to Fill'
    )
)
)
)
  ), 

/* SHIFT RECORD TYPE */

  IF( Cancel_Employee_Held__c = true, 'In a Cancelled Shift',

    /* IF( sirenum__Cancelled__c = true, */

      /* OLD IF( NOT(ISPICKVAL(sirenum__CancellationReason__c , 'Unable to Fill')) && Cancellation_Completed__c = true, */
      /* IF( Cancellation_Completed__c = true, 
      'Shift Cancelled Filled', 'Err Shift Canc Filled'), */

      /* IF( Cancellation_Completed__c = false, 'In a Cancelled Shift', 'Err In a Canc Shift') 

    ), */
     /* Cancel_Employee_Held__c = false */

    IF( Cancellation_Completed__c = true, if( sirenum__Cancelled__c = true, 'Shift Cancelled Filled', 'In a Cancelled Shift'),
/* Cancellation_Completed__c = false */

    IF( ISBLANK( TEXT(Reconfirmed__c)),

      IF( sirenum__Published__c = true && sirenum__Accepted__c = 1,

          IF( Confirmed_With_Facility__c = false, 
          'Allocated',
          IF( sirenum__Scheduled_Start_Time__c >= NOW(), 'Confirmed', 'Completed')
      ),
      IF( Confirmed_With_Facility__c = false, 'Waiting', 'Name Given')



     /* IF( sirenum__Accepted__c = 0, 

        IF( Confirmed_With_Facility__c = false, 'Waiting', 'Name Given'), 


        IF( sirenum__Published__c = true, 

          IF( Confirmed_With_Facility__c = true, 

            IF( sirenum__Scheduled_Start_Time__c >= NOW(), 'Confirmed', 'Completed'), 

            'Allocated'),


          'ERR Accepted TRUE'
        ) */
      ),

      IF(ISPICKVAL( Reconfirmed__c, 'Both'), 'Reconfirm',
        IF(ISPICKVAL( Reconfirmed__c, 'Reconfirmed with Employee'), 'Reconfirm with Employee',
          IF(ISPICKVAL( Reconfirmed__c, 'Reconfirmed with Facility'), 'Reconfirm with Facility',
          'ERR RECONFIRM WITH'
          )
        )
      )        
    ) 
  ))
)
